from typing import List

def maxNumber(nums1: List[int], nums2: List[int], k: int) -> List[int]:
    def build_max_number(nums: List[int], length: int) -> List[int]:
        stack = []
        remaining = len(nums)

        for num in nums:
            while stack and remaining > length - len(stack) and stack[-1] < num:
                stack.pop()
            if len(stack) < length:
                stack.append(num)
            remaining -= 1

        return stack

    def merge(nums1: List[int], nums2: List[int]) -> List[int]:
        result = []
        i, j = 0, 0

        while i < len(nums1) or j < len(nums2):
            if nums1[i:] > nums2[j:]:
                result.append(nums1[i])
                i += 1
            else:
                result.append(nums2[j])
                j += 1

        return result

    # Find the maximum possible number by considering all possible splits between nums1 and nums2
    max_num = []
    for split in range(max(0, k - len(nums2)), min(k, len(nums1)) + 1):
        max_num1 = build_max_number(nums1, split)
        max_num2 = build_max_number(nums2, k - split)
        merged_num = merge(max_num1, max_num2)
        if merged_num > max_num:
            max_num = merged_num

    return max_num

# Example usage:
print(maxNumber([3, 4, 6, 5], [9, 1, 2, 5, 8, 3], 5))  # Output: [9, 8, 6, 5, 3]
print(maxNumber([6, 7], [6, 0, 4], 5))             # Output: [6, 7, 6, 0, 4]
print(maxNumber([3, 9], [8, 9], 3))               # Output: [9, 8, 9]

