from collections import deque

# Definition for a binary tree node.
class TreeNode(object):
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution(object):
    def minDepth(self, root):
        """
        :type root: TreeNode
        :rtype: int
        """
        if not root:
            return 0

        queue = deque([(root, 1)])  # Initialize the queue with the root and its depth

        while queue:
            node, depth = queue.popleft()

            # If the node is a leaf, return its depth
            if not node.left and not node.right:
                return depth

            # Add the left child to the queue with incremented depth
            if node.left:
                queue.append((node.left, depth + 1))

            # Add the right child to the queue with incremented depth
            if node.right:
                queue.append((node.right, depth + 1))

