        """
        :type root: TreeNode
        :rtype: bool
        """
        def inorder_traversal(node, prev=float('-inf')):
            if not node:
                return True

            # Traverse the left subtree
            if not inorder_traversal(node.left, prev):
                return False

            # Check if the current node's value is greater than the previous one
            if node.val <= prev:
                return False

            # Update the previous value
            prev = node.val

            # Traverse the right subtree
            return inorder_traversal(node.right, prev)

        return inorder_traversal(root)

