from collections import deque

class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        if not s:
            return [""]

        # Helper function to check if a string has valid parentheses
        def is_valid(s):
            balance = 0
            for char in s:
                if char == '(':
                    balance += 1
                elif char == ')':
                    balance -= 1
                if balance < 0:
                    return False
            return balance == 0

        # BFS to find all valid strings
        queue = deque([s])
        visited = set()
        visited.add(s)
        found = False
        result = []

        while queue:
            current = queue.popleft()

            # If the current string is valid, add it to the result
            if is_valid(current):
                found = True
                result.append(current)
                continue

            # If we have already found a valid string, stop further exploration
            if found:
                continue

            # Generate all possible strings by removing one parenthesis
            for i in range(len(current)):
                if current[i] in "()":
                    new_string = current[:i] + current[i+1:]
                    if new_string not in visited:
                        visited.add(new_string)
                        queue.append(new_string)

        return result

