class Solution(object):
    def preimageSizeFZF(self, k):
        """
        :type k: int
        :rtype: int
        """

        def count_trailing_zeroes(x):
            count = 0
            while x >= 5:
                x //= 5
                count += x
            return count

        # Binary search to find the range of x where f(x) = k
        low, high = 0, 5 * k + 1

        while low < high:
            mid = (low + high) // 2
            if count_trailing_zeroes(mid) < k:
                low = mid + 1
            else:
                high = mid

        # Check if there is exactly one x such that f(x) = k
        if count_trailing_zeroes(low) == k and count_trailing_zeroes(low + 1) > k:
            return 1
        else:
            return 0

