from collections import deque

class Solution(object):
    def containVirus(self, isInfected):
        """
        :type isInfected: List[List[int]]
        :rtype: int
        """
        m, n = len(isInfected), len(isInfected[0])
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        def bfs(i, j):
            queue = deque([(i, j)])
            visited = set()
            virus = set()
            walls = 0

            while queue:
                x, y = queue.popleft()
                if (x, y) in visited:
                    continue
                visited.add((x, y))

                if isInfected[x][y] == 1:
                    virus.add((x, y))
                else:
                    walls += 1

                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and (nx, ny) not in visited:
                        queue.append((nx, ny))

            return virus, walls

        def count_uninfected_neighbors(x, y):
            count = 0
            for dx, dy in directions:
                nx, ny = x + dx, y + dy
                if 0 <= nx < m and 0 <= ny < n and isInfected[nx][ny] == 0:
                    count += 1
            return count

        total_walls = 0
        while True:
            max_infected_count = 0
            best_virus_set = None
            best_wall_set = None

            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == 1:
                        virus_set, walls = bfs(i, j)
                        if len(virus_set) > max_infected_count:
                            max_infected_count = len(virus_set)
                            best_virus_set = virus_set
                            best_wall_set = walls

            if max_infected_count == 0:
                break

            # Add walls to quarantine the best virus region
            for x, y in best_virus_set:
                isInfected[x][y] = -1

            total_walls += best_wall_set

            # Update the grid to reflect the new state
            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == -1:
                        isInfected[i][j] = 1
                    elif isInfected[i][j] == 0:
                        uninfected_neighbors = count_uninfected_neighbors(i, j)
                        if uninfected_neighbors > 0:
                            isInfected[i][j] = 1
                            total_walls += 1

            # Reset the grid for the next iteration
            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == -1:
                        isInfected[i][j] = 0

        return total_walls

