import heapq

class Solution(object):
    def medianSlidingWindow(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: List[float]
        """
        if not nums or k == 0:
            return []

        # Initialize heaps
        max_heap = []  # Max heap to store the smaller half of the elements
        min_heap = []  # Min heap to store the larger half of the elements

        def rebalance_heaps():
            if len(max_heap) > len(min_heap) + 1:
                heapq.heappush(min_heap, -heapq.heappop(max_heap))
            elif len(min_heap) > len(max_heap):
                heapq.heappush(max_heap, -heapq.heappop(min_heap))

        def get_median():
            if len(max_heap) == len(min_heap):
                return (-max_heap[0] + min_heap[0]) / 2.0
            else:
                return -max_heap[0]

        # Initialize the first window
        for i in range(k):
            heapq.heappush(max_heap, -nums[i])
        rebalance_heaps()

        result = [get_median()]

        # Slide the window across the array
        for i in range(k, len(nums)):
            # Remove the element that is no longer in the window
            if nums[i - k] <= -max_heap[0]:
                heapq.heappop(max_heap)
            else:
                heapq.heappop(min_heap)

            # Add the new element to the appropriate heap
            if nums[i] <= -max_heap[0]:
                heapq.heappush(max_heap, -nums[i])
            else:
                heapq.heappush(min_heap, -nums[i])

            rebalance_heaps()

            # Append the current median to the result
            result.append(get_median())

        return result

