    def isUgly(self, n):
        """
        :type n: int
        :rtype: bool
        """
        # Edge case: if n is less than or equal to 0, it's not an ugly number
        if n <= 0:
            return False

        # Divide n by 2 until it's odd
        while n % 2 == 0:
            n //= 2

        # Divide n by 3 until it's odd
        while n % 3 == 0:
            n //= 3

        # Divide n by 5 until it's odd
        while n % 5 == 0:
            n //= 5

        # If n is reduced to 1, then it's an ugly number
        return n == 1

