class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n + 1))
        self.rank = [0] * (n + 1)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rootX = self.find(x)
        rootY = self.find(y)
        if rootX == rootY:
            return False
        if self.rank[rootX] > self.rank[rootY]:
            self.parent[rootY] = rootX
        elif self.rank[rootX] < self.rank[rootY]:
            self.parent[rootX] = rootY
        else:
            self.parent[rootY] = rootX
            self.rank[rootX] += 1
        return True

class Solution(object):
    def findRedundantDirectedConnection(self, edges):
        """
        :type edges: List[List[int]]
        :rtype: List[int]
        """
        n = len(edges)

        # Step 1: Check for cycles
        uf = UnionFind(n)
        cycle_edge = None
        for u, v in edges:
            if not uf.union(u, v):
                cycle_edge = (u, v)

        if cycle_edge is None:
            return None

        # Step 2: Check for multiple parents
        parent_count = [0] * (n + 1)
        for u, v in edges:
            parent_count[v] += 1

        # Find the node with multiple parents
        multiple_parent_node = None
        for u, v in edges:
            if parent_count[v] == 2:
                multiple_parent_node = v
                break

        if multiple_parent_node is None:
            return cycle_edge

        # Step 3: Determine the redundant edge
        for u, v in reversed(edges):
            if u == multiple_parent_node and v != cycle_edge[1]:
                return [multiple_parent_node, v]

        return None

