        dp = [[[float('-inf')] * n for _ in range(n)] for _ in range(n)]

        # Base case: start from (0, 0) to (n-1, n-1)
        dp[0][0][n-1] = grid[0][0] + grid[n-1][n-1]

        # Directions for moving right, down, left, up
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

