                        continue

                    for di, dj in directions:
                        ni, nj = i + di, j + dj
                        nk, nkj = k + di, n-1-kj

                        if 0 <= ni < n and 0 <= nj < n and 0 <= nk < n and 0 <= nkj < n:
                            dp[i][j][k] = max(dp[i][j][k], dp[ni][nj][nk] + grid[i][j])

                            if i != k:
                                dp[i][j][k] = max(dp[i][j][k], dp[ni][nj][nkj] + grid[i][j] + grid[k][n-1-i])

        # The maximum cherries collected from (0, 0) to (n-1, n-1) and back
        return max(dp[n-1][n-1][n-1], 0)

