class Solution(object):
    def permute(self, nums):
        """
        :type nums: List[int]
        :rtype: List[List[int]]
        """
        result = []

        def backtrack(start):
            if start == len(nums):
                result.append(nums[:])
            else:
                for i in range(start, len(nums)):
                    # Swap the current element with the start element
                    nums[start], nums[i] = nums[i], nums[start]
                    # Recurse with the next starting point
                    backtrack(start + 1)
                    # Backtrack by swapping back to restore the original order
                    nums[start], nums[i] = nums[i], nums[start]

        backtrack(0)
        return result

