        result = []

        # Insert all words into the Trie
        for word in words:
            trie.insert(word)

        # Check each word to see if it can be broken into smaller words
        for word in words:
            if self.can_break(word, trie, 0, set()):
                result.append(word)

        return result

    def can_break(self, word, trie, start, visited):
        if start == len(word):
            return True

        for end in range(start + 1, len(word) + 1):
            if word[start:end] in visited:
                continue
            if trie.search(word[start:end]):
                if self.can_break(word, trie, end, visited | {word[start:end]}):
                    return True
        return False

